--
SET @CGUID := 153321; -- creature start guid
SET @GGUID := 83685; -- gameobject start guid

DELETE FROM `command` WHERE `name` IN (
    'worldstate scourgeinvasion show',
    'worldstate scourgeinvasion state',
    'worldstate scourgeinvasion battleswon',
    'worldstate scourgeinvasion startzone'
);


SET
@scourge_invasion            = 17,
@scourge_boss_in_instance    = 89,
@scourge_winterspring        = 90,
@scourge_tanaris             = 91,
@scourge_azshara             = 92,
@scourge_blasted_lands       = 93,
@scourge_eastern_plaguelands = 94,
@scourge_burning_steppes     = 95,
@scourge_50_invasions_done   = 96,
@scourge_100_invasions_done  = 97,
@scourge_150_invasions_done  = 98,
@scourge_invasions_done      = 99;

DELETE FROM `game_event` WHERE `eventEntry` IN (
    @scourge_boss_in_instance,  @scourge_winterspring, @scourge_tanaris, @scourge_azshara,
    @scourge_blasted_lands,     @scourge_eastern_plaguelands, @scourge_burning_steppes,
    @scourge_50_invasions_done, @scourge_100_invasions_done, @scourge_150_invasions_done, @scourge_invasions_done
);
SET @GAMEEVENT_INTERNAL = 5; -- never handled in GameEventMgr update

-- Scourge Invasion - Boss in instance activation
UPDATE `game_event_creature` SET `eventEntry` = @scourge_boss_in_instance WHERE `guid` IN (248653, 248650, 248654, 248651);
-- missing entry for Lord Blackwood 14695 Scholomance
SET @LORD_BLACKWOOD_ENTRY := 14695;
DELETE FROM `creature` WHERE `guid` = @CGUID AND `id1` = @LORD_BLACKWOOD_ENTRY;
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_boss_in_instance AND `guid` = @CGUID;

-- Scourge Invasion - 50 invasions done
-- Pallid Horror and Argent Dawn Paladin
DELETE FROM `creature` WHERE `guid` BETWEEN @CGUID+1 AND @CGUID+7 AND `id1` IN (16395, 16384);
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_50_invasions_done AND `guid` BETWEEN @CGUID+1 AND @CGUID+7;

-- Scourge Invasion - 100 invasions done
-- Argent Dawn Cleric and Argent Dawn Crusader
DELETE FROM `creature` WHERE `guid` BETWEEN @CGUID+8 AND @CGUID+14 AND `id1` IN (16433, 16435);
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_100_invasions_done AND `guid` BETWEEN @CGUID+8 AND @CGUID+14;

-- Scourge Invasion - 150 invasions done
-- Argent Dawn Champion and Argent Dawn Priest
DELETE FROM `creature` WHERE `guid` BETWEEN @CGUID+15 AND @CGUID+21 AND `id1` IN (16434, 16436);
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_150_invasions_done AND `guid` BETWEEN @CGUID+15 AND @CGUID+21;

-- Scourge Invasion - done
-- Argent Outfitter and Argent Quartermaster
DELETE FROM `creature` WHERE `guid` BETWEEN @CGUID+22 AND @CGUID+27 + 5 AND `id1` IN (16787, 16786);
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_invasions_done AND `guid` BETWEEN @CGUID+22 AND @CGUID+27;

-- Scourge Invasion
-- Skeletal Soldier, Spectral Apparition, Spectral Spirit, Skeletal Trooper
DELETE FROM `creature` WHERE `id1` IN (16422, 16423, 16437, 16438) AND `guid` BETWEEN (@CGUID+28) AND (@CGUID+28)+191;
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_invasion AND `guid` BETWEEN (@CGUID+28) AND (@CGUID+28) + 191;
-- Herald of the Lich King
DELETE FROM `creature` WHERE `guid` BETWEEN (@CGUID+28) + 192 AND (@CGUID+28) + 197 AND `id1` = 16995;
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_invasion AND `guid` BETWEEN (@CGUID+28) + 192 AND (@CGUID+28) + 197;

-- Gameobjects
-- Circle
DELETE FROM `gameobject` WHERE `guid` BETWEEN @GGUID AND @GGUID + 12 AND `id` = 181227;
DELETE FROM `game_event_gameobject` WHERE `eventEntry` = @scourge_invasion AND `guid` BETWEEN @GGUID AND @GGUID + 11;

-- Invasion Zones: Winterspring
-- Winterspring
DELETE FROM `creature` WHERE `guid` BETWEEN (@CGUID+226) AND (@CGUID+226) + 245 AND `id1` IN (16356, 16386, 16421, 16398, 16401);
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_winterspring AND `guid` BETWEEN (@CGUID+226) AND (@CGUID+226) + 245;

-- Tanaris
DELETE FROM `creature` WHERE `guid` BETWEEN @CGUID+472 AND @CGUID+671 AND `id1` = 16356;
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_tanaris AND `guid` BETWEEN (@CGUID+472) AND (@CGUID+472) + 199;

-- Azshara
DELETE FROM `creature` WHERE `guid` BETWEEN (@CGUID+672) AND (@CGUID+672) + 183 AND `id1` IN (16356, 16386, 16398, 16401, 16421);
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_azshara AND `guid` BETWEEN (@CGUID+672) AND (@CGUID+672) + 183;

-- Blasted Lands
DELETE FROM `creature` WHERE `guid` BETWEEN (@CGUID+856) AND (@CGUID+856) + 183 AND `id1` IN (16356, 16401, 16421, 16398, 16386);
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_blasted_lands AND `guid` BETWEEN (@CGUID+856) AND (@CGUID+856) + 183;

-- Eastern Plaguelands
DELETE FROM `creature` WHERE `guid` BETWEEN (@CGUID+1040) AND (@CGUID+1040) + 171 AND `id1` IN (16356, 16386, 16398, 16401, 16421);
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_eastern_plaguelands AND `guid` BETWEEN (@CGUID+1040) AND (@CGUID+1040) + 171;
-- Burning Steppes
DELETE FROM `creature` WHERE `guid` BETWEEN (@CGUID+1212) AND (@CGUID+1212) + 178 AND `id1` IN (16356, 16421, 16401, 16398, 16386);
DELETE FROM `game_event_creature` WHERE `eventEntry` = @scourge_burning_steppes AND `guid` BETWEEN (@CGUID+1212) AND (@CGUID+1212) + 178;

-- Lord Blackwood - Scholomance waypoints
DELETE FROM `waypoint_data` WHERE `id` = @LORD_BLACKWOOD_ENTRY*10 and `point` BETWEEN 1 AND 17;
DELETE FROM `creature_template_addon` WHERE (`entry` = @LORD_BLACKWOOD_ENTRY);

UPDATE `creature_template` SET `ScriptName` = 'npc_pallid_horror' WHERE (`entry` IN (16382, 16394));
UPDATE `creature_template` SET `ScriptName` = 'scourge_invasion_minion' WHERE (`entry` IN (16143, 16383));
UPDATE `creature_template` SET `ScriptName` = 'scourge_invasion_minion_spawner' WHERE (`entry` IN (16306, 16336, 16338));
UPDATE `creature_template` SET `ScriptName` = 'scourge_invasion_mouth' WHERE (`entry` = 16995);
UPDATE `creature_template` SET `ScriptName` = 'scourge_invasion_necropolis' WHERE (`entry` = 16401);
UPDATE `creature_template` SET `ScriptName` = 'scourge_invasion_necropolis_health' WHERE (`entry` = 16421);
UPDATE `creature_template_addon` SET `visibilityDistanceType` = 5 WHERE (`entry` = 16421); -- 3 -> infinite (3000.0f)
UPDATE `creature_template` SET `ScriptName` = 'scourge_invasion_necropolis_proxy' WHERE (`entry` = 16398);
UPDATE `creature_template` SET `ScriptName` = 'scourge_invasion_necropolis_relay' WHERE (`entry` = 16386);
UPDATE `creature_template` SET `ScriptName` = 'scourge_invasion_necrotic_shard' WHERE (`entry` IN (16136, 16172));
UPDATE `creature_template` SET `ScriptName` = 'scourge_invasion_cultist_engineer' WHERE (`entry` = 16230);

UPDATE `gameobject_template` SET `ScriptName` = 'scourge_invasion_go_circle' WHERE (`entry` = 181136);
UPDATE `gameobject_template` SET `ScriptName` = 'scourge_invasion_go_necropolis' WHERE (`entry` IN (181154, 181215, 181223, 181374, 181373));

DELETE FROM `conditions` WHERE (`SourceTypeOrReferenceId` = 13) AND (`SourceEntry` IN (28326, 28365, 28366, 28367, 28373, 28281, 28364, 28032, 28078)) AND (`SourceId` = 0) AND (`ConditionTypeOrReference` = 31) AND (`ConditionTarget` = 0) AND (`ConditionValue1` IN (3, 5)) AND (`ConditionValue2` IN (16136, 16172, 16398, 16386, 16401, 181154, 181215, 181223, 181373, 181374, 181154, 181215, 181223, 181373, 181374, 16398, 16398, 16386, 16386, 1756, 13839, 16136, 16172)) AND (`ConditionValue3` = 0);

-- Herald
DELETE FROM `creature_text` WHERE (`CreatureID` = 16995) AND (`GroupID` IN (0, 1));
